     1→using CSharpLargeApi.Application.DTOs;
     2→using CSharpLargeApi.Application.Interfaces;
     3→using CSharpLargeApi.Application.Mappings;
     4→using CSharpLargeApi.Domain.ValueObjects;
     5→
     6→namespace CSharpLargeApi.Api.Controllers;
     7→
     8→/// <summary>
     9→/// API controller for payment-related operations.
    10→/// Provides endpoints for processing payments, retrying failed payments,
    11→/// and querying payment history.
    12→/// </summary>
    13→public class PaymentController
    14→{
    15→    private readonly IPaymentService _paymentService;
    16→
    17→    /// <summary>
    18→    /// Initializes the controller with the payment service.
    19→    /// </summary>
    20→    public PaymentController(IPaymentService paymentService)
    21→    {
    22→        _paymentService = paymentService ?? throw new ArgumentNullException(nameof(paymentService));
    23→    }
    24→
    25→    /// <summary>
    26→    /// Processes a new payment for the specified user.
    27→    /// Caller #1: PaymentController.ProcessPayment calls IPaymentService.ProcessPayment.
    28→    /// POST /api/payments
    29→    /// </summary>
    30→    public async Task<PaymentDto> ProcessPayment(Guid userId, decimal amount, string currency, string paymentMethodToken, CancellationToken cancellationToken = default)
    31→    {
    32→        var money = new Money(amount, currency);
    33→
    34→        // Caller #1: PaymentController.ProcessPayment calls ProcessPayment
    35→        var payment = await _paymentService.ProcessPayment(
    36→            userId, money, paymentMethodToken, cancellationToken);
    37→
    38→        return PaymentProfile.ToDto(payment);
    39→    }
    40→
    41→    /// <summary>
    42→    /// Retries a previously failed payment with a new or existing payment method.
    43→    /// Caller #2: PaymentController.RetryPayment calls IPaymentService.ProcessPayment.
    44→    /// POST /api/payments/retry
    45→    /// </summary>
    46→    public async Task<PaymentDto> RetryPayment(Guid userId, decimal amount, string currency, string paymentMethodToken, CancellationToken cancellationToken = default)
    47→    {
    48→        var money = new Money(amount, currency);
    49→
    50→        // Caller #2: PaymentController.RetryPayment calls ProcessPayment
    51→        var payment = await _paymentService.ProcessPayment(
    52→            userId, money, paymentMethodToken, cancellationToken);
    53→
    54→        return PaymentProfile.ToDto(payment);
    55→    }
    56→
    57→    /// <summary>
    58→    /// Retrieves a specific payment by its identifier.
    59→    /// GET /api/payments/{id}
    60→    /// </summary>
    61→    public async Task<PaymentDto?> GetPayment(Guid paymentId, CancellationToken cancellationToken = default)
    62→    {
    63→        var payment = await _paymentService.GetPaymentAsync(paymentId, cancellationToken);
    64→        return payment is not null ? PaymentProfile.ToDto(payment) : null;
    65→    }
    66→
    67→    /// <summary>
    68→    /// Lists payments for a specific user with pagination.
    69→    /// GET /api/payments?userId={userId}&skip={skip}&take={take}
    70→    /// </summary>
    71→    public async Task<IReadOnlyList<PaymentDto>> ListPayments(Guid userId, int skip = 0, int take = 20, CancellationToken cancellationToken = default)
    72→    {
    73→        var payments = await _paymentService.GetPaymentsByUserAsync(
    74→            userId, skip, take, cancellationToken);
    75→
    76→        return PaymentProfile.ToDtoList(payments);
    77→    }
    78→
    79→    /// <summary>
    80→    /// Validates a payment method token without creating a charge.
    81→    /// POST /api/payments/validate-method
    82→    /// </summary>
    83→    public async Task<bool> ValidatePaymentMethod(string paymentMethodToken, CancellationToken cancellationToken = default)
    84→    {
    85→        return await _paymentService.ValidatePaymentMethod(paymentMethodToken, cancellationToken);
    86→    }
    87→}
