     1→using CSharpLargeApi.Application.DTOs;
     2→using CSharpLargeApi.Application.Interfaces;
     3→using CSharpLargeApi.Domain.Exceptions;
     4→using CSharpLargeApi.Domain.ValueObjects;
     5→
     6→namespace CSharpLargeApi.Application.Commands.ProcessPayment;
     7→
     8→/// <summary>
     9→/// Handles the ProcessPaymentCommand by orchestrating validation,
    10→/// payment processing, and response mapping.
    11→/// This is a CQRS command handler — caller #4 of ProcessPayment.
    12→/// </summary>
    13→public class ProcessPaymentHandler
    14→{
    15→    private readonly IPaymentService _paymentService;
    16→    private readonly IUserService _userService;
    17→    private readonly INotificationService _notificationService;
    18→
    19→    /// <summary>
    20→    /// Initializes the handler with required dependencies.
    21→    /// </summary>
    22→    public ProcessPaymentHandler(
    23→        IPaymentService paymentService,
    24→        IUserService userService,
    25→        INotificationService notificationService)
    26→    {
    27→        _paymentService = paymentService ?? throw new ArgumentNullException(nameof(paymentService));
    28→        _userService = userService ?? throw new ArgumentNullException(nameof(userService));
    29→        _notificationService = notificationService ?? throw new ArgumentNullException(nameof(notificationService));
    30→    }
    31→
    32→    /// <summary>
    33→    /// Handles the command by validating the user exists, processing the payment,
    34→    /// and sending a confirmation notification.
    35→    /// </summary>
    36→    public async Task<PaymentDto> Handle(ProcessPaymentCommand command, CancellationToken cancellationToken)
    37→    {
    38→        var user = await _userService.GetUserAsync(command.UserId, cancellationToken);
    39→        if (user is null)
    40→        {
    41→            throw new EntityNotFoundException("User", command.UserId);
    42→        }
    43→
    44→        if (!user.IsActive)
    45→        {
    46→            throw new BusinessRuleException(
    47→                "ActiveUserRequired",
    48→                "Cannot process payment for a deactivated user account.",
    49→                "User");
    50→        }
    51→
    52→        var isValidMethod = await _paymentService.ValidatePaymentMethod(
    53→            command.PaymentMethodToken, cancellationToken);
    54→
    55→        if (!isValidMethod)
    56→        {
    57→            throw new BusinessRuleException(
    58→                "ValidPaymentMethodRequired",
    59→                "The provided payment method is invalid or expired.",
    60→                "Payment");
    61→        }
    62→
    63→        var amount = new Money(command.Amount, command.Currency);
    64→
    65→        // Caller #4: ProcessPaymentHandler.Handle calls IPaymentService.ProcessPayment
    66→        var payment = await _paymentService.ProcessPayment(
    67→            command.UserId,
    68→            amount,
    69→            command.PaymentMethodToken,
    70→            cancellationToken);
    71→
    72→        await _notificationService.SendEmailAsync(
    73→            command.UserId,
    74→            "Payment Confirmation",
    75→            $"Your payment of {amount} has been processed successfully. Transaction ID: {payment.Id}",
    76→            cancellationToken);
    77→
    78→        return new PaymentDto
    79→        {
    80→            Id = payment.Id,
    81→            UserId = payment.UserId,
    82→            Amount = payment.Amount.Amount,
    83→            Currency = payment.Amount.Currency,
    84→            Status = payment.Status.ToString(),
    85→            GatewayTransactionId = payment.GatewayTransactionId,
    86→            CreatedAt = payment.CreatedAt
    87→        };
    88→    }
    89→}
    90→

