     1→namespace CSharpLargeApi.Infrastructure.External;
     2→
     3→/// <summary>
     4→/// Client for interacting with the Stripe payment gateway.
     5→/// Handles charge creation, refunds, and payment method validation.
     6→/// </summary>
     7→public class StripeClient
     8→{
     9→    private readonly string _apiKey;
    10→    private readonly string _baseUrl;
    11→
    12→    /// <summary>
    13→    /// Initializes the Stripe client with API credentials.
    14→    /// </summary>
    15→    public StripeClient(string apiKey, string baseUrl = "https://api.stripe.com/v1")
    16→    {
    17→        _apiKey = apiKey ?? throw new ArgumentNullException(nameof(apiKey));
    18→        _baseUrl = baseUrl;
    19→    }
    20→
    21→    /// <summary>
    22→    /// Creates a charge against the specified payment method.
    23→    /// Returns a gateway result with the transaction ID on success.
    24→    /// </summary>
    25→    public async Task<GatewayResult> ChargeAsync(decimal amount, string currency, string paymentMethodToken, CancellationToken cancellationToken = default)
    26→    {
    27→        // Simulate gateway call
    28→        await Task.Delay(1, cancellationToken);
    29→
    30→        if (string.IsNullOrWhiteSpace(paymentMethodToken))
    31→        {
    32→            return new GatewayResult
    33→            {
    34→                Succeeded = false,
    35→                ErrorMessage = "Invalid payment method token."
    36→            };
    37→        }
    38→
    39→        if (amount <= 0)
    40→        {
    41→            return new GatewayResult
    42→            {
    43→                Succeeded = false,
    44→                ErrorMessage = "Charge amount must be positive."
    45→            };
    46→        }
    47→
    48→        return new GatewayResult
    49→        {
    50→            Succeeded = true,
    51→            TransactionId = $"ch_{Guid.NewGuid():N}",
    52→            Amount = amount,
