     3→/// <summary>
     4→/// Pipeline behavior that validates commands before they reach their handlers.
     5→/// If validation fails, a ValidationException is thrown with all errors
     6→/// before any business logic executes.
     7→/// </summary>
     8→/// <typeparam name="TCommand">The command type being validated.</typeparam>
     9→/// <typeparam name="TResult">The result type returned by the handler.</typeparam>
    10→public class ValidationBehavior<TCommand, TResult>
    11→{
    12→    private readonly Func<TCommand, IReadOnlyList<string>>? _validator;
    13→
    14→    /// <summary>
    15→    /// Initializes the behavior with an optional validator function.
    16→    /// </summary>
    17→    public ValidationBehavior(Func<TCommand, IReadOnlyList<string>>? validator = null)
    18→    {
    19→        _validator = validator;
    20→    }
    21→
    22→    /// <summary>
    23→    /// Executes validation before passing the command to the next handler in the pipeline.
    24→    /// Throws an InvalidOperationException if validation errors are found.
    25→    /// </summary>
    26→    public async Task<TResult> Handle(TCommand command, Func<Task<TResult>> next)
    27→    {
    28→        if (_validator is not null)
    29→        {
    30→            var errors = _validator(command);
    31→            if (errors.Count > 0)
    32→            {
    33→                var errorMessage = string.Join("; ", errors);
    34→                throw new InvalidOperationException($"Validation failed: {errorMessage}");
    35→            }
    36→        }
    37→
    38→        return await next();
    39→    }
    40→}
