### 5. Payment Service Implementation - Core Processing

**File:** `/private/var/folders/3f/707q7v5124901v6qkg6y1ck80000gn/T/inari-benchmark-1623432206/src/Infrastructure/Services/PaymentService.cs`

```csharp
public class PaymentService : IPaymentService
{
    private readonly IRepository<Payment> _paymentRepository;
    private readonly StripeClient _stripeClient;
    private readonly INotificationService _notificationService;

    public PaymentService(
        IRepository<Payment> paymentRepository,
        StripeClient stripeClient,
        INotificationService notificationService)
    {
        _paymentRepository = paymentRepository ?? throw new ArgumentNullException(nameof(paymentRepository));
        _stripeClient = stripeClient ?? throw new ArgumentNullException(nameof(stripeClient));
        _notificationService = notificationService ?? throw new ArgumentNullException(nameof(notificationService));
    }

    // Called by 7 non-test callers:
    // 1. PaymentController.ProcessPayment
    // 2. PaymentController.RetryPayment
    // 3. SubscriptionController.RenewSubscription
    // 4. ProcessPaymentHandler.Handle
    // 5. PaymentRetryWorker.RetryFailedPayment
    // 6. InvoiceService.SettleInvoice
    // 7. RefundService.ProcessPartialRefund
    public async Task<Payment> ProcessPayment(
        Guid userId, 
        Money amount, 
        string paymentMethodToken, 
        CancellationToken cancellationToken = default)
    {
        // Error handling step 1: Validate user ID
        if (userId == Guid.Empty)
        {
            throw new BusinessRuleException(
                "ValidUserRequired", 
                "A valid user ID is required to process a payment.");
        }

        // Error handling step 2: Validate amount
        if (amount.Amount <= 0)
        {
            throw new BusinessRuleException(
                "PositiveAmountRequired", 
                "Payment amount must be greater than zero.");
        }

        // Error handling step 3: Validate payment method token
        if (string.IsNullOrWhiteSpace(paymentMethodToken))
        {
            throw new BusinessRuleException(
                "PaymentMethodRequired", 
                "A payment method token is required.");
        }

        // Create payment entity in Pending status
        var payment = Payment.Create(userId, amount);

        try
        {
            // Call Stripe gateway
            var gatewayResult = await _stripeClient.ChargeAsync(
                amount.Amount,
                amount.Currency,
                paymentMethodToken,
                cancellationToken);

            if (gatewayResult.Succeeded)
            {
                // Mark as completed with transaction ID
                payment.MarkAsProcessed(gatewayResult.TransactionId);

                // Send success notification
                await _notificationService.SendEmailAsync(
                    userId,
                    "Payment Successful",
                    $"Your payment of {amount} has been processed. Transaction: {gatewayResult.TransactionId}",
                    cancellationToken);
            }
            else
            {
                // Mark as failed with error message from gateway
                payment.MarkAsFailed(gatewayResult.ErrorMessage ?? "Payment declined by gateway.");
            }
        }
        catch (Exception ex)
        {
            // Error handling: Catch all unhandled exceptions from gateway
            payment.MarkAsFailed($"Payment processing error: {ex.Message}");
        }

        // Persist to repository
        await _paymentRepository.AddAsync(payment, cancellationToken);

        return payment;
    }

    public async Task<Payment> RefundPayment(
        Guid paymentId, 
        string reason, 
        CancellationToken cancellationToken = default)
    {
        var payment = await _paymentRepository.GetByIdAsync(paymentId, cancellationToken);

        // Error handling: Payment not found
        if (payment is null)
        {
            throw new EntityNotFoundException("Payment", paymentId);
        }

        // Error handling: Only completed payments can be refunded
        if (payment.Status != PaymentStatus.Completed)
        {
            throw new BusinessRuleException(
                "CompletedPaymentRequired",
                $"Only completed payments can be refunded. Current status: {payment.Status}");
        }

        // Error handling: Gateway transaction ID required
        if (string.IsNullOrWhiteSpace(payment.GatewayTransactionId))
        {
            throw new BusinessRuleException(
                "GatewayTransactionRequired",
                "Cannot refund a payment without a gateway transaction ID.");
        }

        var refundResult = await _stripeClient.RefundAsync(
            payment.GatewayTransactionId,
            payment.Amount.Amount,
            cancellationToken);

        if (refundResult.Succeeded)
        {
            payment.MarkAsRefunded();

            await _notificationService.SendEmailAsync(
                payment.UserId,
                "Refund Processed",
                $"Your refund of {payment.Amount} has been processed. Reason: {reason}",
                cancellationToken);
        }
        else
        {
            // Error handling: Refund failed at gateway
            throw new BusinessRuleException(
                "RefundFailed",
                $"Refund failed: {refundResult.ErrorMessage}");
        }

        await _paymentRepository.SaveChangesAsync(cancellationToken);
        return payment;
    }

    public async Task<bool> ValidatePaymentMethod(
        string paymentMethodToken, 
        CancellationToken cancellationToken = default)
    {
        if (string.IsNullOrWhiteSpace(paymentMethodToken))
        {
            return false;
        }

        return await _stripeClient.ValidatePaymentMethodAsync(paymentMethodToken, cancellationToken);
    }

    public async Task<Payment?> GetPaymentAsync(
        Guid paymentId, 
        CancellationToken cancellationToken = default)
    {
        return await _paymentRepository.GetByIdAsync(paymentId, cancellationToken);
    }

    public async Task<IReadOnlyList<Payment>> GetPaymentsByUserAsync(
        Guid userId, 
        int skip = 0, 
        int take = 20, 
        CancellationToken cancellationToken = default)
    {
        var allPayments = await _paymentRepository.GetAllAsync(cancellationToken);
        return allPayments
            .Where(p => p.UserId == userId)
            .OrderByDescending(p => p.CreatedAt)
            .Skip(skip)
            .Take(take)
            .ToList()
            .AsReadOnly();
    }
