public class StripeClient
{
    private readonly string _apiKey;
    private readonly string _baseUrl;

    public StripeClient(string apiKey, string baseUrl = "https://api.stripe.com/v1")
    {
        _apiKey = apiKey ?? throw new ArgumentNullException(nameof(apiKey));
        _baseUrl = baseUrl;
    }

    public async Task<GatewayResult> ChargeAsync(
        decimal amount, 
        string currency, 
        string paymentMethodToken, 
        CancellationToken cancellationToken = default)
    {
        await Task.Delay(1, cancellationToken);

        // Error handling: Invalid token
        if (string.IsNullOrWhiteSpace(paymentMethodToken))
        {
            return new GatewayResult
            {
                Succeeded = false,
                ErrorMessage = "Invalid payment method token."
            };
        }

        // Error handling: Invalid amount
        if (amount <= 0)
        {
            return new GatewayResult
            {
                Succeeded = false,
                ErrorMessage = "Charge amount must be positive."
            };
        }

        // Success case
        return new GatewayResult
        {
            Succeeded = true,
            TransactionId = $"ch_{Guid.NewGuid():N}",
            Amount = amount,
            Currency = currency
        };
    }

    public async Task<GatewayResult> RefundAsync(
        string transactionId, 
        decimal amount, 
        CancellationToken cancellationToken = default)
    {
        await Task.Delay(1, cancellationToken);

        // Error handling: Missing transaction ID
        if (string.IsNullOrWhiteSpace(transactionId))
        {
            return new GatewayResult
            {
                Succeeded = false,
                ErrorMessage = "Transaction ID is required for refund."
            };
        }

        return new GatewayResult
        {
            Succeeded = true,
            TransactionId = $"re_{Guid.NewGuid():N}",
            Amount = amount
        };
    }

    public async Task<bool> ValidatePaymentMethodAsync(
        string paymentMethodToken, 
        CancellationToken cancellationToken = default)
    {
        await Task.Delay(1, cancellationToken);
        return !string.IsNullOrWhiteSpace(paymentMethodToken) && paymentMethodToken.Length >= 8;
    }
}

public class GatewayResult
{
    public bool Succeeded { get; set; }
    public string TransactionId { get; set; } = string.Empty;
    public decimal Amount { get; set; }
    public string Currency { get; set; } = string.Empty;
    public string? ErrorMessage { get; set; }
}
